public void noMoreInteractionsWanted(Invocation undesired, List<VerificationAwareInvocation> invocations) {
        ScenarioPrinter scenarioPrinter = new ScenarioPrinter();
        String scenario = scenarioPrinter.print(invocations);

        String mockName;
        try {
            Object mock = undesired.getMock();
            mockName = mock != null ? mock.getClass().getSimpleName() : "null";
        } catch (Throwable t) {
            mockName = "mock";
        }

        throw new NoInteractionsWanted(join(
                "No interactions wanted here:",
                new LocationImpl(),
                "But found this interaction on mock '" + mockName + "':",
                undesired.getLocation(),
                scenario
        ));
    }

public void noMoreInteractionsWantedInOrder(Invocation undesired) {
        String mockName;
        try {
            Object mock = undesired.getMock();
            mockName = mock != null ? mock.getClass().getSimpleName() : "null";
        } catch (Throwable t) {
            mockName = "mock";
        }

        throw new VerificationInOrderFailure(join(
                "No interactions wanted here:",
                new LocationImpl(),
                "But found this interaction on mock '" + mockName + "':",
                undesired.getLocation()
        ));
    }

private String exceptionCauseMessageIfAvailable(Exception details) {
        Throwable cause = details != null ? details.getCause() : null;
        String message = cause != null ? cause.getMessage() : (details != null ? details.getMessage() : null);
        return message;
    }
